INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20052, 0, 1, 1, 10, "そうかい。\nじゃあまずは、焚火の枝を集める運命を\n受け入れてもらえるかい？", 105611, 11, 0, 1200520010, 0);
