INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20162, 0, 1, 1, 10, "ねねね！\nみんなで記念撮影しよ？\nあとで見返したら絶対エモいっしょ！", 101611, 11, 0, 1201620005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20162, "", "", "", "", "", 0, 91, "", 1201620006, "");
