INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20172, 0, 1, 1, 10, "こうして遠出するのもいいもんだ。\n道中で強い魔物とかが出てくれば、\n面白いケンカもできそうだしさ。", 106511, 11, 0, 1201720005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20172, "", "", "", "", "", 0, 91, "", 1201720006, "");
