INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20192, 0, 1, 1, 10, "よーし！　ネネカと一緒に冒険だ！\nせっかくだし、何か悪いことするか？\n七冠とやれば派手になりそうだしさ！", 106111, 11, 0, 1201920005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20192, "", "", "", "", "", 0, 91, "", 1201920006, "");
