INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20282, "", 0, "", 0, "vo_travel_talk_20028_00", "vo_travel_talk", 21, "", 1202820004, "");
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20282, 0, 1, 1, 10, "アハハ、不機嫌顔だね。ま、いきなり\n引っ張り出されたらそりゃ不満か。\nほらほら、冒険だよ、楽しまなくちゃ！", 106811, 11, 0, 1202820005, 0);
INSERT INTO `v1_034613f85425c2ba1c78f0709ed5cd5c28494e98631154b054b8f1a1e8d533b4` VALUES (20282, "", "", "", "", "", 0, 91, "", 1202820006, "");
